void myproject::thread_hdltv_gen() {
    const char* dump_tv = std::getenv("AP_WRITE_TV");
    if (!(dump_tv && string(dump_tv) == "on")) return;

    wait();

    mHdltvinHandle << "[ " << endl;
    mHdltvoutHandle << "[ " << endl;
    int ap_cycleNo = 0;
    while (1) {
        wait();
        const char* mComma = ap_cycleNo == 0 ? " " : ", " ;
        mHdltvinHandle << mComma << "{"  <<  " \"q_conv2d_batchnorm_input_V_data_0_V_TDATA\" :  \"" << q_conv2d_batchnorm_input_V_data_0_V_TDATA.read() << "\" ";
        mHdltvoutHandle << mComma << "{"  <<  " \"layer22_out_V_data_0_V_TDATA\" :  \"" << layer22_out_V_data_0_V_TDATA.read() << "\" ";
        mHdltvoutHandle << " , " <<  " \"layer22_out_V_data_1_V_TDATA\" :  \"" << layer22_out_V_data_1_V_TDATA.read() << "\" ";
        mHdltvoutHandle << " , " <<  " \"layer22_out_V_data_2_V_TDATA\" :  \"" << layer22_out_V_data_2_V_TDATA.read() << "\" ";
        mHdltvoutHandle << " , " <<  " \"layer22_out_V_data_3_V_TDATA\" :  \"" << layer22_out_V_data_3_V_TDATA.read() << "\" ";
        mHdltvoutHandle << " , " <<  " \"layer22_out_V_data_4_V_TDATA\" :  \"" << layer22_out_V_data_4_V_TDATA.read() << "\" ";
        mHdltvinHandle << " , " <<  " \"ap_rst_n\" :  \"" << ap_rst_n.read() << "\" ";
        mHdltvinHandle << " , " <<  " \"q_conv2d_batchnorm_input_V_data_0_V_TVALID\" :  \"" << q_conv2d_batchnorm_input_V_data_0_V_TVALID.read() << "\" ";
        mHdltvoutHandle << " , " <<  " \"q_conv2d_batchnorm_input_V_data_0_V_TREADY\" :  \"" << q_conv2d_batchnorm_input_V_data_0_V_TREADY.read() << "\" ";
        mHdltvinHandle << " , " <<  " \"ap_start\" :  \"" << ap_start.read() << "\" ";
        mHdltvoutHandle << " , " <<  " \"layer22_out_V_data_0_V_TVALID\" :  \"" << layer22_out_V_data_0_V_TVALID.read() << "\" ";
        mHdltvinHandle << " , " <<  " \"layer22_out_V_data_0_V_TREADY\" :  \"" << layer22_out_V_data_0_V_TREADY.read() << "\" ";
        mHdltvoutHandle << " , " <<  " \"layer22_out_V_data_1_V_TVALID\" :  \"" << layer22_out_V_data_1_V_TVALID.read() << "\" ";
        mHdltvinHandle << " , " <<  " \"layer22_out_V_data_1_V_TREADY\" :  \"" << layer22_out_V_data_1_V_TREADY.read() << "\" ";
        mHdltvoutHandle << " , " <<  " \"layer22_out_V_data_2_V_TVALID\" :  \"" << layer22_out_V_data_2_V_TVALID.read() << "\" ";
        mHdltvinHandle << " , " <<  " \"layer22_out_V_data_2_V_TREADY\" :  \"" << layer22_out_V_data_2_V_TREADY.read() << "\" ";
        mHdltvoutHandle << " , " <<  " \"layer22_out_V_data_3_V_TVALID\" :  \"" << layer22_out_V_data_3_V_TVALID.read() << "\" ";
        mHdltvinHandle << " , " <<  " \"layer22_out_V_data_3_V_TREADY\" :  \"" << layer22_out_V_data_3_V_TREADY.read() << "\" ";
        mHdltvoutHandle << " , " <<  " \"layer22_out_V_data_4_V_TVALID\" :  \"" << layer22_out_V_data_4_V_TVALID.read() << "\" ";
        mHdltvinHandle << " , " <<  " \"layer22_out_V_data_4_V_TREADY\" :  \"" << layer22_out_V_data_4_V_TREADY.read() << "\" ";
        mHdltvoutHandle << " , " <<  " \"ap_done\" :  \"" << ap_done.read() << "\" ";
        mHdltvoutHandle << " , " <<  " \"ap_ready\" :  \"" << ap_ready.read() << "\" ";
        mHdltvoutHandle << " , " <<  " \"ap_idle\" :  \"" << ap_idle.read() << "\" ";
        mHdltvinHandle << "}" << std::endl;
        mHdltvoutHandle << "}" << std::endl;
        ap_cycleNo++;
    }
}

